#[pyfunction]
fn _boom(x: i64) -> PyResult<i64> {
    if x < 0 {
        return Err(PyErr::new::<pyo3::exceptions::PyRuntimeError, _>("ValueError(\"no negatives\")"));
    }
    Ok(x * 2)
}

#[pyfunction]
fn cached_factorial(n: i64) -> PyResult<i64> {
    if n <= 1 {
        Ok(1)
    }
    Ok(n * cached_factorial(n - 1))
}

