#[pymodule]
fn xray_rustified(m: &Bound<'_, PyModule>) -> PyResult<()> {
    m.add_function(wrap_pyfunction!(score_pair_detailed, m)?)?;
    m.add_function(wrap_pyfunction!(semantic_similarity, m)?)?;
    m.add_function(wrap_pyfunction!(_classify_token, m)?)?;
    m.add_function(wrap_pyfunction!(_classify_name, m)?)?;
    m.add_function(wrap_pyfunction!(assert_tokenize_snake_case, m)?)?;
    m.add_function(wrap_pyfunction!(assert_tokenize_camel_case, m)?)?;
    m.add_function(wrap_pyfunction!(_strip_markdown_fences, m)?)?;
    m.add_function(wrap_pyfunction!(_token_ngram_similarity, m)?)?;
    m.add_function(wrap_pyfunction!(name_similarity, m)?)?;
    m.add_function(wrap_pyfunction!(callgraph_overlap, m)?)?;
    m.add_function(wrap_pyfunction!(_safe_repr, m)?)?;
    m.add_function(wrap_pyfunction!(_make_func, m)?)?;
    m.add_function(wrap_pyfunction!(_delta_int, m)?)?;
    m.add_function(wrap_pyfunction!(_delta_float, m)?)?;
    m.add_function(wrap_pyfunction!(_detect_gpu, m)?)?;
    m.add_function(wrap_pyfunction!(_boom, m)?)?;
    m.add_function(wrap_pyfunction!(cached_factorial, m)?)?;
    m.add_function(wrap_pyfunction!(_make_class, m)?)?;
    m.add_function(wrap_pyfunction!(_make_smell, m)?)?;
    m.add_function(wrap_pyfunction!(llm_transpile_function, m)?)?;
    m.add_function(wrap_pyfunction!(run_smell_phase, m)?)?;
    m.add_function(wrap_pyfunction!(run_duplicate_phase, m)?)?;
    m.add_function(wrap_pyfunction!(_ast_histogram_similarity, m)?)?;
    m.add_function(wrap_pyfunction!(tmp_py_file, m)?)?;
    m.add_function(wrap_pyfunction!(_query_llm, m)?)?;
    m.add_function(wrap_pyfunction!(_retry, m)?)?;
    m.add_function(wrap_pyfunction!(generate_llm_vectors, m)?)?;
    m.add_function(wrap_pyfunction!(fix_all, m)?)?;
    m.add_function(wrap_pyfunction!(get_cached_llm_transpiler, m)?)?;
    m.add_function(wrap_pyfunction!(__init__, m)?)?;
    Ok(())
}

fn main() -> PyResult<()> {
    pyo3::append_to_inittab!(xray_rustified);
    pyo3::prepare_freethreaded_python();
    Python::with_gil(|py| {
        let sys = py.import("sys")?;
        let path_obj = sys.getattr("path")?;
        let path: &Bound<'_, PyList> = path_obj.downcast()?;
        let current_dir = std::env::current_dir().unwrap();
        path.insert(0, current_dir.to_str().unwrap())?;
        let args: Vec<String> = std::env::args().collect();
        sys.setattr("argv", args.into_py(py))?;
        let x_ray_exe = py.import("x_ray_exe")?;
        x_ray_exe.call_method0("main")?;
        Ok(())
    })
}